async (page) => {
  var title = "图解 Blaze · 第 22 章 · Spring Boot + Blaze-Persistence 实战：项目搭建与基础 CRUD — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 22 章 · Spring Boot + Blaze-Persistence 实战：项目搭建与基础 CRUD</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">电商订单管理 · Maven 依赖 · JPA Entity · Blaze 配置 · Entity View 投影 · Spring Data Repository · Service/Controller · 错误处理 · 陷阱警示</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">前 21 章从原理到优化，构建了完整的知识图谱。从本章开始，我们将把所有知识点<strong style=\"color:#1a1a2e;font-weight:700;\">落地到一个真实的电商订单管理系统</strong>——从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">pom.xml</code> 的第一行依赖写起，到 Controller 返回第一条 JSON，让你亲手搭建一个可运行的 Spring Boot + Blaze-Persistence 项目。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">项目搭建：分层架构 · Maven 依赖 · 5 个 JPA Entity · Blaze <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Configuration</code> 配置</li><li style=\"margin-bottom:4px;font-size:13px;\">数据层：Entity View 投影体系 · EntityViewRepository 零 SQL · Service 层 CRUD</li><li style=\"margin-bottom:4px;font-size:13px;\">Web 层：RESTful Controller + Keyset 分页 · 统一异常处理</li><li style=\"margin-bottom:4px;font-size:13px;\">质量保障：Entity View vs 原生 JPA 对比 · 4 类常见陷阱规避</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 2 章 · 环境搭建</span> 的基础配置，<span style=\"color:#1e6fff;\">第 4 章 · Entity View</span> 的投影概念，<span style=\"color:#1e6fff;\">第 6 章 · Updatable Entity View</span> 的可更新视图，<span style=\"color:#1e6fff;\">第 10 章 · 分页</span> 的 Keyset 分页，<span style=\"color:#1e6fff;\">第 12 章 · Spring 集成</span> 的 Spring Data 集成基础。</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.1 项目架构总览</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">在动手写代码之前，先看清全局。下图展示了我们要构建的电商订单管理系统的<strong style=\"color:#1a1a2e;font-weight:700;\">分层架构</strong>——从 HTTP 请求进入到 SQL 落盘，每一层的职责一目了然。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-1 电商订单系统分层架构</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n🌐 前端 / API 客户端 (HTTP JSON)\n\n↓\n\n🎮 Controller 层 — @RestController\n路由 · 参数校验 · 响应封装\n\n↓\n\n⚙️ Service 层 — @Service @Transactional\n业务逻辑 · 事务边界\n\n↓\n\n\n📦 Repository\nEntityViewRepository<br/>Spring Data 派生查询\n\n\n🔧 CriteriaBuilder\nCriteriaBuilderFactory<br/>动态复杂查询\n\n\n↓\n\n\n📐 EntityViewManager\nView ↔ Entity 映射\n\n\n🏗️ CriteriaBuilderFactory\nSQL 构建 · 渲染\n\n\n↓\n\n\nEntityManager · Hibernate 6.2\n一级缓存 · 脏检查 · SQL 方言\n\n\n↓\n\n🐘 PostgreSQL\ncustomers · orders · products · categories\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Blaze-Persistence 在 Spring 生态中扮演的角色</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">纯 Spring Data JPA 项目的数据流是 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">Controller → Service → JpaRepository → EntityManager → DB</code>。引入 Blaze-Persistence 后，架构增加了三个关键组件：</p></section>\n\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">对比维度</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">纯 Spring Data JPA</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Spring Data + Blaze-Persistence</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">查询生成</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code> 全列</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">按 View 字段精确 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">DTO 转换</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">手动 MapStruct / BeanUtils</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Entity View 自动投影</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">分页</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET/LIMIT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Keyset 分页 + OFFSET 兼容</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">更新</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">先查再改 (read-modify-write)</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">UpdatableEntityView</code> 脏追踪</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">复杂查询</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">JPQL 字符串或 JPA Criteria</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">类型安全 CriteriaBuilder</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">N+1 问题</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">需 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityGraph</code> 逐个配置</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@BatchFetch</code> / MULTISET 一行搞定</td></tr></table></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">项目目录结构</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">ecommerce-order-service/<br/>├── pom.xml<br/>├── src/main/java/com/example/ecommerce/<br/>│   ├── EcommerceApplication.java<br/>│   ├── config/<br/>│   │   └── BlazeConfig.java              ← Blaze-Persistence 配置<br/>│   ├── entity/<br/>│   │   ├── Customer.java<br/>│   │   ├── Product.java<br/>│   │   ├── Order.java<br/>│   │   ├── OrderItem.java<br/>│   │   ├── Category.java<br/>│   │   └── OrderStatus.java              ← 枚举<br/>│   ├── view/<br/>│   │   ├── customer/<br/>│   │   │   ├── CustomerListView.java<br/>│   │   │   ├── CustomerDetailView.java<br/>│   │   │   ├── CustomerCreateView.java<br/>│   │   │   └── CustomerUpdateView.java<br/>│   │   └── order/<br/>│   │       ├── OrderSummaryView.java<br/>│   │       ├── OrderDetailView.java<br/>│   │       └── OrderItemView.java<br/>│   ├── repository/<br/>│   │   ├── CustomerRepository.java<br/>│   │   └── OrderRepository.java<br/>│   ├── service/<br/>│   │   ├── CustomerService.java<br/>│   │   └── OrderService.java<br/>│   ├── controller/<br/>│   │   ├── CustomerController.java<br/>│   │   └── OrderController.java<br/>│   ├── dto/<br/>│   │   ├── CustomerCreateRequest.java<br/>│   │   ├── CreateOrderRequest.java<br/>│   │   └── ErrorResponse.java<br/>│   └── exception/<br/>│       └── GlobalExceptionHandler.java<br/>└── src/main/resources/<br/>    ├── application.yml<br/>    └── db/migration/<br/>        └── V1__init_schema.sql</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.2 Maven 配置 — 完整 pom.xml</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">依赖管理是项目的根基。Blaze-Persistence 由多个模块组成，与 Spring Boot 的集成需要<strong style=\"color:#1a1a2e;font-weight:700;\">精确对齐版本</strong>。下图展示了各依赖模块之间的关系：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-3 Blaze-Persistence 依赖关系图</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n你的应用 — 业务代码\n\n↓\n\n\ncore-api\nCriteriaBuilder 接口\n\n\nentity-view-api\n@EntityView 注解\n\n\n↓\n\n\ncore-impl\nSQL 渲染引擎\n\n\nentity-view-impl\nView 代理生成\n\n\n↓\n\n\nintegration-hibernate-6.2\nHibernate 6.x 适配\n\n\nintegration-spring-data-3.3\nSpring Data 桥接\n\n\n↓\n\nSpring Boot Starters + PostgreSQL 驱动\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整 pom.xml</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">&lt;?xml version=\"1.0\" encoding=\"UTF-8\"?&gt;<br/>&lt;project xmlns=\"http:<span style=\"color:#6c7086;font-style:italic;\">//maven.apache.org/POM/4.0.0\"</span><br/>         xmlns:xsi=\"http:<span style=\"color:#6c7086;font-style:italic;\">//www.w3.org/2001/XMLSchema-instance\"</span><br/>         xsi:schemaLocation=\"http:<span style=\"color:#6c7086;font-style:italic;\">//maven.apache.org/POM/4.0.0</span><br/>         https:<span style=\"color:#6c7086;font-style:italic;\">//maven.apache.org/xsd/maven-4.0.0.xsd\"&gt;</span><br/>    &lt;modelVersion&gt;4.0.0&lt;/modelVersion&gt;<br/><br/>    &lt;parent&gt;<br/>        &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>        &lt;artifactId&gt;spring-boot-starter-parent&lt;/artifactId&gt;<br/>        &lt;version&gt;3.3.0&lt;/version&gt;<br/>    &lt;/parent&gt;<br/><br/>    &lt;groupId&gt;com.example&lt;/groupId&gt;<br/>    &lt;artifactId&gt;ecommerce-order-service&lt;/artifactId&gt;<br/>    &lt;version&gt;1.0.0-SNAPSHOT&lt;/version&gt;<br/><br/>    &lt;properties&gt;<br/>        &lt;java.version&gt;21&lt;/java.version&gt;<br/>        &lt;blaze-persistence.version&gt;1.6.12&lt;/blaze-persistence.version&gt;<br/>    &lt;/properties&gt;<br/><br/>    &lt;dependencies&gt;<br/>        &lt;!-- ======= Spring Boot ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>            &lt;artifactId&gt;spring-boot-starter-data-jpa&lt;/artifactId&gt;<br/>        &lt;/dependency&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>            &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt;<br/>        &lt;/dependency&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>            &lt;artifactId&gt;spring-boot-starter-validation&lt;/artifactId&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= Blaze-Persistence Core ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-core-api&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>        &lt;/dependency&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-core-impl&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>            &lt;scope&gt;runtime&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= Blaze-Persistence Hibernate 集成 ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-integration-hibernate-6.2&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>            &lt;scope&gt;runtime&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= Blaze-Persistence Entity View ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-entity-view-api&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>        &lt;/dependency&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-entity-view-impl&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>            &lt;scope&gt;runtime&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= Blaze-Persistence Spring Data 集成 ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.blazebit&lt;/groupId&gt;<br/>            &lt;artifactId&gt;blaze-persistence-integration-spring-data-3.3&lt;/artifactId&gt;<br/>            &lt;version&gt;${blaze-persistence.version}&lt;/version&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= 数据库 ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;org.postgresql&lt;/groupId&gt;<br/>            &lt;artifactId&gt;postgresql&lt;/artifactId&gt;<br/>            &lt;scope&gt;runtime&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/><br/>        &lt;!-- ======= 测试 ======= --&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;<br/>            &lt;artifactId&gt;spring-boot-starter-test&lt;/artifactId&gt;<br/>            &lt;scope&gt;test&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/>        &lt;dependency&gt;<br/>            &lt;groupId&gt;com.h2database&lt;/groupId&gt;<br/>            &lt;artifactId&gt;h2&lt;/artifactId&gt;<br/>            &lt;scope&gt;test&lt;/scope&gt;<br/>        &lt;/dependency&gt;<br/>    &lt;/dependencies&gt;<br/>&lt;/project&gt;</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">版本对齐规则：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">integration-hibernate-6.2</code> 对应 Hibernate 6.2+（Spring Boot 3.x 默认）。如果你使用 Spring Boot 2.x（Hibernate 5.x），则需要 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">integration-hibernate-5.6</code>。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">integration-spring-data-3.3</code> 对应 Spring Data 3.3+（Spring Boot 3.3.x）。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">application.yml 配置</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">spring:<br/>  datasource:<br/>    url: jdbc:postgresql:<span style=\"color:#6c7086;font-style:italic;\">//localhost:5432/ecommerce</span><br/>    username: ecommerce_user<br/>    password: ${DB_PASSWORD}<br/>    hikari:<br/>      maximum-pool-size: 20<br/>      minimum-idle: 5<br/><br/>  jpa:<br/>    hibernate:<br/>      ddl-auto: validate<br/>    properties:<br/>      hibernate:<br/>        format_sql: true<br/>        default_batch_fetch_size: 16<br/>        jdbc:<br/>          batch_size: 50<br/>        order_inserts: true<br/>        order_updates: true<br/><br/>  jackson:<br/>    serialization:<br/>      write-dates-as-timestamps: false<br/><br/>logging:<br/>  level:<br/>    org.hibernate.SQL: DEBUG<br/>    org.hibernate.type.descriptor.sql: TRACE<br/>    com.blazebit.persistence: DEBUG</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.3 JPA Entity 定义</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">我们的电商系统包含 5 个核心实体。先看它们之间的关系：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-4 电商领域 ER 模型</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n\nCUSTOMER\n\nbigintidPK\nvarcharname\nvarcharemailUK\nvarcharphone\ntimestampcreated_at\ntimestampupdated_at\n\n\n\n1──────*\n下单\n\n\nORDER\n\nbigintidPK\nbigintcustomer_idFK\nvarcharstatus\ndecimaltotal_amount\nvarchartenant_id\ntimestampcreated_at\n\n\n\n1──────*\n包含\n\n\nORDER_ITEM\n\nbigintidPK\nbigintorder_idFK\nbigintproduct_idFK\nintquantity\ndecimalunit_price\ndecimalsubtotal\n\n\n\n*──────1\n商品\n\n\nPRODUCT\n\nbigintidPK\nvarcharname\nvarcharskuUK\ndecimalprice\nintstock_quantity\nbigintcategory_idFK\n\n\n\n*──────1\n归类\n\n\nCATEGORY\n\nbigintidPK\nvarcharname\nbigintparent_idFK ↻\n\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderStatus 枚举</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public enum OrderStatus {<br/>    PENDING,        <span style=\"color:#6c7086;font-style:italic;\">// 待支付</span><br/>    PAID,           <span style=\"color:#6c7086;font-style:italic;\">// 已支付</span><br/>    PROCESSING,     <span style=\"color:#6c7086;font-style:italic;\">// 处理中</span><br/>    SHIPPED,        <span style=\"color:#6c7086;font-style:italic;\">// 已发货</span><br/>    DELIVERED,      <span style=\"color:#6c7086;font-style:italic;\">// 已送达</span><br/>    CANCELLED,      <span style=\"color:#6c7086;font-style:italic;\">// 已取消</span><br/>    REFUNDED        <span style=\"color:#6c7086;font-style:italic;\">// 已退款</span><br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-5 订单状态机</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Customer 实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.entity;<br/><br/>import jakarta.persistence.*;<br/>import java.time.LocalDateTime;<br/>import java.util.ArrayList;<br/>import java.util.List;<br/><br/>@Entity<br/>@Table(name = \"customers\")<br/>public class Customer {<br/><br/>    @Id<br/>    @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    @Column(nullable = false, length = 100)<br/>    private String name;<br/><br/>    @Column(nullable = false, unique = true, length = 200)<br/>    private String email;<br/><br/>    @Column(length = 20)<br/>    private String phone;<br/><br/>    @Column(name = \"created_at\", nullable = false, updatable = false)<br/>    private LocalDateTime createdAt;<br/><br/>    @Column(name = \"updated_at\")<br/>    private LocalDateTime updatedAt;<br/><br/>    @OneToMany(mappedBy = \"customer\")<br/>    private List&lt;Order&gt; orders = new ArrayList&lt;&gt;();<br/><br/>    @PrePersist<br/>    protected void onCreate() {<br/>        this.createdAt = LocalDateTime.now();<br/>        this.updatedAt = this.createdAt;<br/>    }<br/><br/>    @PreUpdate<br/>    protected void onUpdate() {<br/>        this.updatedAt = LocalDateTime.now();<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Order 实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.entity;<br/><br/>import jakarta.persistence.*;<br/>import java.math.BigDecimal;<br/>import java.time.LocalDateTime;<br/>import java.util.ArrayList;<br/>import java.util.List;<br/><br/>@Entity<br/>@Table(name = \"orders\", indexes = {<br/>    @Index(name = \"idx_order_customer\", columnList = \"customer_id\"),<br/>    @Index(name = \"idx_order_status\", columnList = \"status\"),<br/>    @Index(name = \"idx_order_tenant\", columnList = \"tenant_id\"),<br/>    @Index(name = \"idx_order_created\", columnList = \"created_at DESC\")<br/>})<br/>public class Order {<br/><br/>    @Id<br/>    @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"customer_id\", nullable = false)<br/>    private Customer customer;<br/><br/>    @Enumerated(EnumType.STRING)<br/>    @Column(nullable = false, length = 20)<br/>    private OrderStatus status;<br/><br/>    @Column(name = \"total_amount\", nullable = false, precision = 12, scale = 2)<br/>    private BigDecimal totalAmount;<br/><br/>    @Column(name = \"tenant_id\", nullable = false, length = 50)<br/>    private String tenantId;<br/><br/>    @OneToMany(mappedBy = \"order\", cascade = CascadeType.ALL, orphanRemoval = true)<br/>    private List&lt;OrderItem&gt; items = new ArrayList&lt;&gt;();<br/><br/>    @Column(name = \"created_at\", nullable = false, updatable = false)<br/>    private LocalDateTime createdAt;<br/><br/>    @Version<br/>    private Integer version;<br/><br/>    @PrePersist<br/>    protected void onCreate() {<br/>        this.createdAt = LocalDateTime.now();<br/>        if (this.status == null) {<br/>            this.status = OrderStatus.PENDING;<br/>        }<br/>    }<br/><br/>    public void addItem(OrderItem item) {<br/>        items.add(item);<br/>        item.setOrder(this);<br/>    }<br/><br/>    public void removeItem(OrderItem item) {<br/>        items.remove(item);<br/>        item.setOrder(null);<br/>    }<br/><br/>    public void recalculateTotal() {<br/>        this.totalAmount = items.stream()<br/>            .map(OrderItem::getSubtotal)<br/>            .reduce(BigDecimal.ZERO, BigDecimal::add);<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderItem 实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.entity;<br/><br/>import jakarta.persistence.*;<br/>import java.math.BigDecimal;<br/><br/>@Entity<br/>@Table(name = \"order_items\", indexes = {<br/>    @Index(name = \"idx_item_order\", columnList = \"order_id\"),<br/>    @Index(name = \"idx_item_product\", columnList = \"product_id\")<br/>})<br/>public class OrderItem {<br/><br/>    @Id<br/>    @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"order_id\", nullable = false)<br/>    private Order order;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"product_id\", nullable = false)<br/>    private Product product;<br/><br/>    @Column(nullable = false)<br/>    private int quantity;<br/><br/>    @Column(name = \"unit_price\", nullable = false, precision = 10, scale = 2)<br/>    private BigDecimal unitPrice;<br/><br/>    @Column(nullable = false, precision = 12, scale = 2)<br/>    private BigDecimal subtotal;<br/><br/>    @PrePersist<br/>    @PreUpdate<br/>    protected void calculateSubtotal() {<br/>        this.subtotal = this.unitPrice.multiply(BigDecimal.valueOf(this.quantity));<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Product 实体</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.entity;<br/><br/>import jakarta.persistence.*;<br/>import java.math.BigDecimal;<br/><br/>@Entity<br/>@Table(name = \"products\", indexes = {<br/>    @Index(name = \"idx_product_sku\", columnList = \"sku\", unique = true),<br/>    @Index(name = \"idx_product_category\", columnList = \"category_id\")<br/>})<br/>public class Product {<br/><br/>    @Id<br/>    @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    @Column(nullable = false, length = 200)<br/>    private String name;<br/><br/>    @Column(nullable = false, unique = true, length = 50)<br/>    private String sku;<br/><br/>    @Column(nullable = false, precision = 10, scale = 2)<br/>    private BigDecimal price;<br/><br/>    @Column(name = \"stock_quantity\", nullable = false)<br/>    private int stockQuantity;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"category_id\")<br/>    private Category category;<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Category 实体（自关联树形结构）</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.entity;<br/><br/>import jakarta.persistence.*;<br/>import java.util.ArrayList;<br/>import java.util.List;<br/><br/>@Entity<br/>@Table(name = \"categories\")<br/>public class Category {<br/><br/>    @Id<br/>    @GeneratedValue(strategy = GenerationType.IDENTITY)<br/>    private Long id;<br/><br/>    @Column(nullable = false, length = 100)<br/>    private String name;<br/><br/>    @ManyToOne(fetch = FetchType.LAZY)<br/>    @JoinColumn(name = \"parent_id\")<br/>    private Category parent;<br/><br/>    @OneToMany(mappedBy = \"parent\")<br/>    private List&lt;Category&gt; children = new ArrayList&lt;&gt;();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">数据库初始化脚本</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- V1__init_schema.sql (Flyway)<br/>CREATE TABLE categories (<br/>    id          BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,<br/>    name        VARCHAR(100) NOT NULL,<br/>    parent_id   BIGINT REFERENCES categories(id)<br/>);<br/><br/>CREATE TABLE customers (<br/>    id          BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,<br/>    name        VARCHAR(100)  NOT NULL,<br/>    email       VARCHAR(200)  NOT NULL UNIQUE,<br/>    phone       VARCHAR(20),<br/>    created_at  TIMESTAMP     NOT NULL DEFAULT now(),<br/>    updated_at  TIMESTAMP<br/>);<br/><br/>CREATE TABLE products (<br/>    id              BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,<br/>    name            VARCHAR(200)   NOT NULL,<br/>    sku             VARCHAR(50)    NOT NULL UNIQUE,<br/>    price           NUMERIC(10,2)  NOT NULL,<br/>    stock_quantity  INT            NOT NULL DEFAULT 0,<br/>    category_id     BIGINT REFERENCES categories(id)<br/>);<br/><br/>CREATE TABLE orders (<br/>    id            BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,<br/>    customer_id   BIGINT         NOT NULL REFERENCES customers(id),<br/>    status        VARCHAR(20)    NOT NULL DEFAULT 'PENDING',<br/>    total_amount  NUMERIC(12,2)  NOT NULL DEFAULT 0,<br/>    tenant_id     VARCHAR(50)    NOT NULL,<br/>    created_at    TIMESTAMP      NOT NULL DEFAULT now(),<br/>    version       INT            NOT NULL DEFAULT 0<br/>);<br/><br/>CREATE TABLE order_items (<br/>    id           BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,<br/>    order_id     BIGINT         NOT NULL REFERENCES orders(id) ON DELETE CASCADE,<br/>    product_id   BIGINT         NOT NULL REFERENCES products(id),<br/>    quantity     INT            NOT NULL,<br/>    unit_price   NUMERIC(10,2)  NOT NULL,<br/>    subtotal     NUMERIC(12,2)  NOT NULL<br/>);<br/><br/>CREATE INDEX idx_order_customer ON orders(customer_id);<br/>CREATE INDEX idx_order_status   ON orders(status);<br/>CREATE INDEX idx_order_tenant   ON orders(tenant_id);<br/>CREATE INDEX idx_order_created  ON orders(created_at DESC);<br/>CREATE INDEX idx_item_order     ON order_items(order_id);<br/>CREATE INDEX idx_item_product   ON order_items(product_id);</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.4 Blaze-Persistence 配置</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">整个 Blaze-Persistence 的 Spring Boot 集成只需<strong style=\"color:#1a1a2e;font-weight:700;\">一个配置类</strong>。下图展示了配置类创建的两个核心 Bean 与其他组件的交互关系：</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-6 BlazeConfig Bean 初始化流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Spring Boot</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">BlazeConfig</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilderFactory</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManagerFactory</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewConfiguration</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 注册 SQL 渲染器[BR]关联 Hibernate 方言</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 编译所有 EntityView[BR]生成代理类[BR]绑定到 CBF</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 EntityViewRepository[BR]自动注入 EVM + CBF</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">BlazeConfig.java 完整代码</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.config;<br/><br/>import com.blazebit.persistence.Criteria;<br/>import com.blazebit.persistence.CriteriaBuilderFactory;<br/>import com.blazebit.persistence.spi.CriteriaBuilderConfiguration;<br/>import com.blazebit.persistence.view.EntityViewManager;<br/>import com.blazebit.persistence.view.spi.EntityViewConfiguration;<br/>import com.blazebit.persistence.spring.data.repository.config.EnableBlazeRepositories;<br/>import com.blazebit.persistence.view.EntityViews;<br/>import com.blazebit.persistence.spring.data.impl.repository.BlazePersistenceRepositoryFactoryBean;<br/>import jakarta.persistence.EntityManagerFactory;<br/>import org.springframework.beans.factory.config.ConfigurableBeanFactory;<br/>import org.springframework.context.annotation.*;<br/><br/>@Configuration<br/>@EnableEntityViews(basePackages = \"com.example.ecommerce.view\")<br/>@EnableBlazeRepositories(<br/>    basePackages = \"com.example.ecommerce.repository\",<br/>    repositoryFactoryBeanClass = BlazePersistenceRepositoryFactoryBean.class<br/>)<br/>public class BlazeConfig {<br/><br/>    @Bean<br/>    @Scope(ConfigurableBeanFactory.SCOPE_SINGLETON)<br/>    public CriteriaBuilderFactory criteriaBuilderFactory(<br/>            EntityManagerFactory emf) {<br/>        CriteriaBuilderConfiguration config = Criteria.getDefault();<br/>        return config.createCriteriaBuilderFactory(emf);<br/>    }<br/><br/>    @Bean<br/>    @Scope(ConfigurableBeanFactory.SCOPE_SINGLETON)<br/>    public EntityViewManager entityViewManager(<br/>            CriteriaBuilderFactory cbf,<br/>            EntityViewConfiguration entityViewConfiguration) {<br/>        return entityViewConfiguration.createEntityViewManager(cbf);<br/>    }<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">@EnableEntityViews</strong> 扫描指定包下所有带 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EntityView</code> 注解的接口/抽象类，自动注册到 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewConfiguration</code>。<strong style=\"color:#1a1a2e;font-weight:700;\">@EnableBlazeRepositories</strong> 将 Spring Data 的 Repository 工厂替换为 Blaze 的实现——所有继承 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewRepository</code> 的接口都会自动注入 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code>。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">启动类</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce;<br/><br/>import org.springframework.boot.SpringApplication;<br/>import org.springframework.boot.autoconfigure.SpringBootApplication;<br/><br/>@SpringBootApplication<br/>public class EcommerceApplication {<br/>    public static void main(String[] args) {<br/>        SpringApplication.run(EcommerceApplication.class, args);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">配置验证——启动日志关键行</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 启动成功后应看到如下日志：</span><br/>INFO  c.b.p.v.i.EntityViewManagerImpl :<br/>  Registered entity view 'CustomerListView' for entity 'Customer'<br/>  Registered entity view 'CustomerDetailView' for entity 'Customer'<br/>  Registered entity view 'CustomerCreateView' for entity 'Customer'<br/>  Registered entity view 'CustomerUpdateView' for entity 'Customer'<br/>  Registered entity view 'OrderSummaryView' for entity 'Order'<br/>  Registered entity view 'OrderDetailView' for entity 'Order'<br/>  Registered entity view 'OrderItemView' for entity 'OrderItem'<br/><br/>INFO  c.b.p.s.d.i.r.BlazePersistenceRepositoryFactoryBean :<br/>  Created repository: CustomerRepository<br/>  Created repository: OrderRepository</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.5 Entity View 定义 — DTO 投影</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Entity View 是 Blaze-Persistence 最强大的特性之一——用<strong style=\"color:#1a1a2e;font-weight:700;\">接口声明</strong>替代手动 DTO 映射。一个实体可以有多个 View，分别用于列表展示、详情查询、创建和更新。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-7 Customer Entity View 投影体系</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">Customer</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;JPA Entity&gt;&gt; · Long id · String name · String email · String phone …</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CustomerListView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@EntityView&gt;&gt; · Long getId · String getName · String getEmail · long getOrderCount</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CustomerDetailView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@EntityView&gt;&gt; · String getPhone · LocalDateTime getCreatedAt · List~OrderSummaryView~ getRecentOrders</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CustomerCreateView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@CreatableEntityView&gt;&gt; · String getName · String getEmail · String getPhone</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CustomerUpdateView</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;@UpdatableEntityView&gt;&gt; · Long getId · String getName · String getEmail</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerListView — 列表精简视图</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.customer;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.IdMapping;<br/>import com.blazebit.persistence.view.Mapping;<br/>import com.example.ecommerce.entity.Customer;<br/><br/>@EntityView(Customer.class)<br/>public interface CustomerListView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    String getName();<br/><br/>    String getEmail();<br/><br/>    @Mapping(\"SIZE(orders)\")<br/>    long getOrderCount();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">SQL 投影效果：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"SIZE(orders)\")</code> 会生成 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT c.id, c.name, c.email, (SELECT COUNT(*) FROM orders o WHERE o.customer_id = c.id) AS orderCount</code>——只查 3 个字段 + 1 个子查询，而非 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code> 加载全部列和关联。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerDetailView — 详情嵌套视图</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.customer;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.Mapping;<br/>import com.example.ecommerce.entity.Customer;<br/>import com.example.ecommerce.view.order.OrderSummaryView;<br/>import java.time.LocalDateTime;<br/>import java.util.List;<br/><br/>@EntityView(Customer.class)<br/>public interface CustomerDetailView extends CustomerListView {<br/><br/>    String getPhone();<br/><br/>    LocalDateTime getCreatedAt();<br/><br/>    @Mapping(\"orders\")<br/>    List&lt;OrderSummaryView&gt; getRecentOrders();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerCreateView — 创建视图</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.customer;<br/><br/>import com.blazebit.persistence.view.CreatableEntityView;<br/>import com.blazebit.persistence.view.EntityView;<br/>import com.example.ecommerce.entity.Customer;<br/><br/>@CreatableEntityView<br/>@EntityView(Customer.class)<br/>public interface CustomerCreateView {<br/><br/>    String getName();<br/>    void setName(String name);<br/><br/>    String getEmail();<br/>    void setEmail(String email);<br/><br/>    String getPhone();<br/>    void setPhone(String phone);<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerUpdateView — 更新视图</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.customer;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.IdMapping;<br/>import com.blazebit.persistence.view.UpdatableEntityView;<br/>import com.example.ecommerce.entity.Customer;<br/><br/>@UpdatableEntityView<br/>@EntityView(Customer.class)<br/>public interface CustomerUpdateView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    String getName();<br/>    void setName(String name);<br/><br/>    String getEmail();<br/>    void setEmail(String email);<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderSummaryView — 订单摘要</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.order;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.IdMapping;<br/>import com.example.ecommerce.entity.Order;<br/>import com.example.ecommerce.entity.OrderStatus;<br/>import java.math.BigDecimal;<br/>import java.time.LocalDateTime;<br/><br/>@EntityView(Order.class)<br/>public interface OrderSummaryView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    OrderStatus getStatus();<br/><br/>    BigDecimal getTotalAmount();<br/><br/>    LocalDateTime getCreatedAt();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderDetailView — 订单详情</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.order;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.Mapping;<br/>import com.example.ecommerce.entity.Order;<br/>import java.util.List;<br/><br/>@EntityView(Order.class)<br/>public interface OrderDetailView extends OrderSummaryView {<br/><br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();<br/><br/>    @Mapping(\"customer.email\")<br/>    String getCustomerEmail();<br/><br/>    @Mapping(\"customer.id\")<br/>    Long getCustomerId();<br/><br/>    List&lt;OrderItemView&gt; getItems();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderItemView — 订单明细</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.view.order;<br/><br/>import com.blazebit.persistence.view.EntityView;<br/>import com.blazebit.persistence.view.IdMapping;<br/>import com.blazebit.persistence.view.Mapping;<br/>import com.example.ecommerce.entity.OrderItem;<br/>import java.math.BigDecimal;<br/><br/>@EntityView(OrderItem.class)<br/>public interface OrderItemView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    @Mapping(\"product.name\")<br/>    String getProductName();<br/><br/>    @Mapping(\"product.sku\")<br/>    String getProductSku();<br/><br/>    int getQuantity();<br/><br/>    BigDecimal getUnitPrice();<br/><br/>    BigDecimal getSubtotal();<br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-8 Entity View 继承体系与 SQL 投影列映射</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\nCustomerListView\nid · name · email<br/>SIZE(orders)\n\n\nCustomerDetailView\n← 继承 List 的 4 列<br/>phone · createdAt<br/>orders → OrderSummaryView\n\n\nSQL: 列表查询\nSELECT c.id, c.name,<br/>c.email, (SELECT COUNT(*))\n\n\nSQL: 详情查询\nSELECT c.id, c.name, c.email,<br/>(SELECT COUNT(*)),<br/>c.phone, c.created_at<br/>LEFT JOIN orders\n\n</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.6 Spring Data Repository</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Blaze-Persistence 提供了 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewRepository</code> 替代 Spring Data 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpaRepository</code>——继承它后，所有派生查询方法自动返回 Entity View 而非 Entity。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-9 Repository 接口继承体系</p><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">CustomerRepository</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;自定义&gt;&gt; · findByNameContainingIgnoreCase · findAll</p></section><section style=\"margin:4px 0;padding:6px 12px;border:1px solid #1e6fff;border-radius:5px;background:#f5f5f5;\"><p style=\"margin:0;font-size:12px;font-weight:700;color:#1e6fff;\">OrderRepository</p><p style=\"margin:2px 0 0;font-size:10px;color:#888;font-family:Consolas,monospace;\">&lt;&lt;自定义&gt;&gt; · findByCustomerIdAndStatus · findAll</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerRepository</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.repository;<br/><br/>import com.blazebit.persistence.spring.data.repository.EntityViewRepository;<br/>import com.blazebit.persistence.spring.data.repository.EntityViewSpecificationExecutor;<br/>import com.blazebit.persistence.spring.data.repository.KeysetAwarePage;<br/>import com.blazebit.persistence.spring.data.repository.KeysetPageable;<br/>import com.example.ecommerce.view.customer.CustomerListView;<br/>import org.springframework.stereotype.Repository;<br/>import org.springframework.transaction.annotation.Transactional;<br/>import java.util.List;<br/><br/>@Repository<br/>@Transactional(readOnly = true)<br/>public interface CustomerRepository<br/>        extends EntityViewRepository&lt;CustomerListView, Long&gt;,<br/>                EntityViewSpecificationExecutor&lt;CustomerListView, Long&gt; {<br/><br/>    List&lt;CustomerListView&gt; findByNameContainingIgnoreCase(String name);<br/><br/>    KeysetAwarePage&lt;CustomerListView&gt; findAll(KeysetPageable pageable);<br/><br/>    List&lt;CustomerListView&gt; findByEmailContainingIgnoreCase(String email);<br/><br/>    boolean existsByEmail(String email);<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderRepository</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.repository;<br/><br/>import com.blazebit.persistence.spring.data.repository.EntityViewRepository;<br/>import com.blazebit.persistence.spring.data.repository.KeysetAwarePage;<br/>import com.blazebit.persistence.spring.data.repository.KeysetPageable;<br/>import com.blazebit.persistence.view.EntityViewSetting;<br/>import com.example.ecommerce.entity.OrderStatus;<br/>import com.example.ecommerce.view.order.OrderSummaryView;<br/>import org.springframework.stereotype.Repository;<br/>import org.springframework.transaction.annotation.Transactional;<br/>import java.util.List;<br/><br/>@Repository<br/>@Transactional(readOnly = true)<br/>public interface OrderRepository<br/>        extends EntityViewRepository&lt;OrderSummaryView, Long&gt; {<br/><br/>    List&lt;OrderSummaryView&gt; findByCustomerId(Long customerId);<br/><br/>    List&lt;OrderSummaryView&gt; findByCustomerIdAndStatus(<br/>            Long customerId, OrderStatus status);<br/><br/>    List&lt;OrderSummaryView&gt; findByStatus(OrderStatus status);<br/><br/>    KeysetAwarePage&lt;OrderSummaryView&gt; findAll(KeysetPageable pageable);<br/><br/>    long countByCustomerId(Long customerId);<br/><br/>    long countByStatus(OrderStatus status);<br/>}</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Spring Data 派生查询 + Entity View 的组合效果非常强大——方法名里声明查询条件，返回值直接是 View 接口，生成的 SQL 只投影 View 声明的列：</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 调用 customerRepo.findByNameContainingIgnoreCase(\"张\")</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 生成的 SQL：</span><br/>SELECT c.id, c.name, c.email,<br/>       (SELECT COUNT(*) FROM orders o WHERE o.customer_id = c.id)<br/>FROM customers c<br/>WHERE UPPER(c.name) LIKE UPPER('%张%')<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 对比纯 JPA 的 findByNameContainingIgnoreCase：</span><br/>SELECT c.id, c.name, c.email, c.phone,<br/>       c.created_at, c.updated_at        -- 多出 3 列<br/>FROM customers c<br/>WHERE UPPER(c.name) LIKE UPPER('%张%')<br/>-- 且返回的是 Customer Entity，还需手动转 DTO</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.7 Service 层</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Service 层是事务边界和业务逻辑的核心。Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 提供了完整的 CRUD API，配合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CreatableEntityView</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">UpdatableEntityView</code> 实现类型安全的创建和更新。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-10 Service 层 CRUD 操作流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Controller</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Service</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityViewManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">PostgreSQL</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 === 创建 (Create) ===</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 === 更新 (Update) ===</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 脏追踪：只更新变更字段</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 === 删除 (Delete) ===</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerService 完整实现</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.service;<br/><br/>import com.blazebit.persistence.view.EntityViewManager;<br/>import com.blazebit.persistence.spring.data.repository.KeysetAwarePage;<br/>import com.blazebit.persistence.spring.data.repository.KeysetPageable;<br/>import com.example.ecommerce.repository.CustomerRepository;<br/>import com.example.ecommerce.view.customer.*;<br/>import jakarta.persistence.EntityManager;<br/>import jakarta.persistence.EntityNotFoundException;<br/>import org.springframework.stereotype.Service;<br/>import org.springframework.transaction.annotation.Transactional;<br/>import java.util.List;<br/><br/>@Service<br/>@Transactional<br/>public class CustomerService {<br/><br/>    private final CustomerRepository customerRepo;<br/>    private final EntityViewManager evm;<br/>    private final EntityManager em;<br/><br/>    public CustomerService(CustomerRepository customerRepo,<br/>                           EntityViewManager evm,<br/>                           EntityManager em) {<br/>        this.customerRepo = customerRepo;<br/>        this.evm = evm;<br/>        this.em = em;<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Create ----</span><br/>    public CustomerDetailView create(CustomerCreateView createView) {<br/>        evm.save(em, createView);<br/>        em.flush();<br/>        return evm.find(em, CustomerDetailView.class, createView.getId());<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Read (单条) ----</span><br/>    @Transactional(readOnly = true)<br/>    public CustomerDetailView findById(Long id) {<br/>        CustomerDetailView view = evm.find(em, CustomerDetailView.class, id);<br/>        if (view == null) {<br/>            throw new EntityNotFoundException(<br/>                \"Customer not found: id=\" + id);<br/>        }<br/>        return view;<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Read (列表 + Keyset 分页) ----</span><br/>    @Transactional(readOnly = true)<br/>    public KeysetAwarePage&lt;CustomerListView&gt; findAll(<br/>            KeysetPageable pageable) {<br/>        return customerRepo.findAll(pageable);<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Read (搜索) ----</span><br/>    @Transactional(readOnly = true)<br/>    public List&lt;CustomerListView&gt; searchByName(String keyword) {<br/>        return customerRepo.findByNameContainingIgnoreCase(keyword);<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Update ----</span><br/>    public CustomerDetailView update(Long id,<br/>                                     CustomerUpdateView updateView) {<br/>        if (!id.equals(updateView.getId())) {<br/>            throw new IllegalArgumentException(<br/>                \"Path id and body id mismatch\");<br/>        }<br/>        evm.save(em, updateView);<br/>        em.flush();<br/>        return evm.find(em, CustomerDetailView.class, id);<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// ---- Delete ----</span><br/>    public void delete(Long id) {<br/>        CustomerDetailView existing = evm.find(<br/>            em, CustomerDetailView.class, id);<br/>        if (existing == null) {<br/>            throw new EntityNotFoundException(<br/>                \"Customer not found: id=\" + id);<br/>        }<br/>        evm.remove(em, CustomerListView.class, id);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderService 完整实现</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.service;<br/><br/>import com.blazebit.persistence.CriteriaBuilderFactory;<br/>import com.blazebit.persistence.view.EntityViewManager;<br/>import com.example.ecommerce.dto.CreateOrderRequest;<br/>import com.example.ecommerce.entity.*;<br/>import com.example.ecommerce.repository.OrderRepository;<br/>import com.example.ecommerce.view.order.*;<br/>import jakarta.persistence.EntityManager;<br/>import jakarta.persistence.EntityNotFoundException;<br/>import org.springframework.stereotype.Service;<br/>import org.springframework.transaction.annotation.Transactional;<br/>import java.math.BigDecimal;<br/>import java.util.List;<br/>import java.util.Map;<br/><br/>@Service<br/>@Transactional<br/>public class OrderService {<br/><br/>    private final OrderRepository orderRepo;<br/>    private final EntityViewManager evm;<br/>    private final EntityManager em;<br/>    private final CriteriaBuilderFactory cbf;<br/><br/>    public OrderService(OrderRepository orderRepo,<br/>                        EntityViewManager evm,<br/>                        EntityManager em,<br/>                        CriteriaBuilderFactory cbf) {<br/>        this.orderRepo = orderRepo;<br/>        this.evm = evm;<br/>        this.em = em;<br/>        this.cbf = cbf;<br/>    }<br/><br/>    public OrderDetailView createOrder(CreateOrderRequest req) {<br/>        Order order = new Order();<br/>        order.setCustomer(em.getReference(Customer.class,<br/>                                          req.getCustomerId()));<br/>        order.setTenantId(req.getTenantId());<br/>        order.setStatus(OrderStatus.PENDING);<br/><br/>        for (CreateOrderRequest.ItemRequest item : req.getItems()) {<br/>            Product product = em.find(Product.class,<br/>                                      item.getProductId());<br/>            if (product == null) {<br/>                throw new EntityNotFoundException(<br/>                    \"Product not found: \" + item.getProductId());<br/>            }<br/>            if (product.getStockQuantity() &lt; item.getQuantity()) {<br/>                throw new IllegalStateException(<br/>                    \"Insufficient stock for: \" + product.getSku());<br/>            }<br/><br/>            OrderItem orderItem = new OrderItem();<br/>            orderItem.setProduct(product);<br/>            orderItem.setQuantity(item.getQuantity());<br/>            orderItem.setUnitPrice(product.getPrice());<br/>            orderItem.setSubtotal(product.getPrice()<br/>                .multiply(BigDecimal.valueOf(item.getQuantity())));<br/>            order.addItem(orderItem);<br/><br/>            product.setStockQuantity(<br/>                product.getStockQuantity() - item.getQuantity());<br/>        }<br/><br/>        order.recalculateTotal();<br/>        em.persist(order);<br/>        em.flush();<br/><br/>        return evm.find(em, OrderDetailView.class, order.getId());<br/>    }<br/><br/>    @Transactional(readOnly = true)<br/>    public OrderDetailView findById(Long id) {<br/>        OrderDetailView view = evm.find(<br/>            em, OrderDetailView.class, id);<br/>        if (view == null) {<br/>            throw new EntityNotFoundException(<br/>                \"Order not found: id=\" + id);<br/>        }<br/>        return view;<br/>    }<br/><br/>    @Transactional(readOnly = true)<br/>    public List&lt;OrderSummaryView&gt; findByCustomer(Long customerId) {<br/>        return orderRepo.findByCustomerId(customerId);<br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 订单状态机推进</span><br/>    private static final Map&lt;OrderStatus, List&lt;OrderStatus&gt;&gt;<br/>        VALID_TRANSITIONS = Map.of(<br/>            OrderStatus.PENDING,    List.of(OrderStatus.PAID,<br/>                                            OrderStatus.CANCELLED),<br/>            OrderStatus.PAID,       List.of(OrderStatus.PROCESSING,<br/>                                            OrderStatus.REFUNDED),<br/>            OrderStatus.PROCESSING, List.of(OrderStatus.SHIPPED),<br/>            OrderStatus.SHIPPED,    List.of(OrderStatus.DELIVERED),<br/>            OrderStatus.DELIVERED,  List.of(OrderStatus.REFUNDED)<br/>        );<br/><br/>    public OrderDetailView updateStatus(Long id,<br/>                                        OrderStatus newStatus) {<br/>        Order order = em.find(Order.class, id);<br/>        if (order == null) {<br/>            throw new EntityNotFoundException(<br/>                \"Order not found: id=\" + id);<br/>        }<br/><br/>        List&lt;OrderStatus&gt; allowed = VALID_TRANSITIONS<br/>            .getOrDefault(order.getStatus(), List.of());<br/>        if (!allowed.contains(newStatus)) {<br/>            throw new IllegalStateException(String.format(<br/>                \"Invalid transition: %s → %s. Allowed: %s\",<br/>                order.getStatus(), newStatus, allowed));<br/>        }<br/><br/>        order.setStatus(newStatus);<br/>        em.flush();<br/><br/>        return evm.find(em, OrderDetailView.class, id);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">请求 DTO</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.dto;<br/><br/>import jakarta.validation.Valid;<br/>import jakarta.validation.constraints.*;<br/>import java.util.List;<br/><br/>public class CustomerCreateRequest {<br/>    @NotBlank(message = \"Name is required\")<br/>    @Size(max = 100)<br/>    private String name;<br/><br/>    @NotBlank(message = \"Email is required\")<br/>    @Email<br/>    private String email;<br/><br/>    @Size(max = 20)<br/>    private String phone;<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}<br/><br/>public class CreateOrderRequest {<br/>    @NotNull<br/>    private Long customerId;<br/><br/>    @NotBlank<br/>    private String tenantId;<br/><br/>    @Valid @NotEmpty<br/>    private List&lt;ItemRequest&gt; items;<br/><br/>    public static class ItemRequest {<br/>        @NotNull<br/>        private Long productId;<br/>        @Min(1)<br/>        private int quantity;<br/>        <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>    }<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// getters &amp; setters ...</span><br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.8 REST Controller</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">Controller 层职责单一：路由、参数校验、调用 Service、返回响应。Entity View 可以直接被 Jackson 序列化为 JSON，无需额外的 DTO 转换层。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CustomerController</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.controller;<br/><br/>import com.blazebit.persistence.spring.data.repository.KeysetAwarePage;<br/>import com.blazebit.persistence.spring.data.repository.KeysetPageRequest;<br/>import com.blazebit.persistence.spring.data.repository.KeysetPageable;<br/>import com.example.ecommerce.dto.CustomerCreateRequest;<br/>import com.example.ecommerce.service.CustomerService;<br/>import com.example.ecommerce.view.customer.*;<br/>import jakarta.validation.Valid;<br/>import org.springframework.data.domain.Sort;<br/>import org.springframework.http.HttpStatus;<br/>import org.springframework.web.bind.annotation.*;<br/>import java.util.List;<br/><br/>@RestController<br/>@RequestMapping(\"/api/customers\")<br/>public class CustomerController {<br/><br/>    private final CustomerService customerService;<br/><br/>    public CustomerController(CustomerService customerService) {<br/>        this.customerService = customerService;<br/>    }<br/><br/>    @GetMapping<br/>    public KeysetAwarePage&lt;CustomerListView&gt; list(<br/>            @RequestParam(defaultValue = \"0\") int page,<br/>            @RequestParam(defaultValue = \"20\") int size) {<br/>        KeysetPageable pageable = KeysetPageRequest.of(<br/>            page, size, Sort.by(Sort.Direction.DESC, \"id\"));<br/>        return customerService.findAll(pageable);<br/>    }<br/><br/>    @GetMapping(\"/{id}\")<br/>    public CustomerDetailView getById(@PathVariable Long id) {<br/>        return customerService.findById(id);<br/>    }<br/><br/>    @GetMapping(\"/search\")<br/>    public List&lt;CustomerListView&gt; search(<br/>            @RequestParam String name) {<br/>        return customerService.searchByName(name);<br/>    }<br/><br/>    @PostMapping<br/>    @ResponseStatus(HttpStatus.CREATED)<br/>    public CustomerDetailView create(<br/>            @Valid @RequestBody CustomerCreateRequest req) {<br/>        CustomerCreateView createView = customerService<br/>            .getEntityViewManager()<br/>            .create(CustomerCreateView.class);<br/>        createView.setName(req.getName());<br/>        createView.setEmail(req.getEmail());<br/>        createView.setPhone(req.getPhone());<br/>        return customerService.create(createView);<br/>    }<br/><br/>    @PutMapping(\"/{id}\")<br/>    public CustomerDetailView update(<br/>            @PathVariable Long id,<br/>            @Valid @RequestBody CustomerCreateRequest req) {<br/>        CustomerUpdateView updateView = customerService<br/>            .getEntityViewManager()<br/>            .find(customerService.getEntityManager(),<br/>                  CustomerUpdateView.class, id);<br/>        if (updateView == null) {<br/>            throw new jakarta.persistence.EntityNotFoundException(<br/>                \"Customer not found: id=\" + id);<br/>        }<br/>        updateView.setName(req.getName());<br/>        updateView.setEmail(req.getEmail());<br/>        return customerService.update(id, updateView);<br/>    }<br/><br/>    @DeleteMapping(\"/{id}\")<br/>    @ResponseStatus(HttpStatus.NO_CONTENT)<br/>    public void delete(@PathVariable Long id) {<br/>        customerService.delete(id);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">OrderController</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.controller;<br/><br/>import com.example.ecommerce.dto.CreateOrderRequest;<br/>import com.example.ecommerce.entity.OrderStatus;<br/>import com.example.ecommerce.service.OrderService;<br/>import com.example.ecommerce.view.order.*;<br/>import jakarta.validation.Valid;<br/>import org.springframework.http.HttpStatus;<br/>import org.springframework.web.bind.annotation.*;<br/>import java.util.List;<br/>import java.util.Map;<br/><br/>@RestController<br/>@RequestMapping(\"/api/orders\")<br/>public class OrderController {<br/><br/>    private final OrderService orderService;<br/><br/>    public OrderController(OrderService orderService) {<br/>        this.orderService = orderService;<br/>    }<br/><br/>    @PostMapping<br/>    @ResponseStatus(HttpStatus.CREATED)<br/>    public OrderDetailView createOrder(<br/>            @Valid @RequestBody CreateOrderRequest req) {<br/>        return orderService.createOrder(req);<br/>    }<br/><br/>    @GetMapping(\"/{id}\")<br/>    public OrderDetailView getOrder(@PathVariable Long id) {<br/>        return orderService.findById(id);<br/>    }<br/><br/>    @GetMapping(\"/customer/{customerId}\")<br/>    public List&lt;OrderSummaryView&gt; getByCustomer(<br/>            @PathVariable Long customerId) {<br/>        return orderService.findByCustomer(customerId);<br/>    }<br/><br/>    @PatchMapping(\"/{id}/status\")<br/>    public OrderDetailView updateStatus(<br/>            @PathVariable Long id,<br/>            @RequestBody Map&lt;String, String&gt; body) {<br/>        OrderStatus newStatus = OrderStatus.valueOf(<br/>            body.get(\"status\"));<br/>        return orderService.updateStatus(id, newStatus);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">完整 API 端点一览</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Method</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Path</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">描述</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">返回类型</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">客户列表（Keyset 分页）</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">KeysetAwarePage<CustomerListView></code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers/{id}</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">客户详情</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CustomerDetailView</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers/search?name=</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">按名称搜索</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">List<CustomerListView></code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">POST</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">创建客户</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CustomerDetailView</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PUT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers/{id}</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">更新客户</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CustomerDetailView</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">DELETE</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/customers/{id}</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">删除客户</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">204 No Content</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">POST</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/orders</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">创建订单</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OrderDetailView</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/orders/{id}</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">订单详情</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OrderDetailView</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">GET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/orders/customer/{id}</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">客户订单列表</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">List<OrderSummaryView></code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">PATCH</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">/api/orders/{id}/status</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">更新订单状态</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OrderDetailView</code></td></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.9 错误处理</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">统一的错误处理是 REST API 的基础设施。我们通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ControllerAdvice</code> 拦截所有异常，返回一致的 JSON 错误响应。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">ErrorResponse DTO</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.dto;<br/><br/>import java.time.LocalDateTime;<br/><br/>public record ErrorResponse(<br/>    int status,<br/>    String error,<br/>    String message,<br/>    String path,<br/>    LocalDateTime timestamp<br/>) {<br/>    public ErrorResponse(int status, String error,<br/>                         String message, String path) {<br/>        this(status, error, message, path, LocalDateTime.now());<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">GlobalExceptionHandler</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">package com.example.ecommerce.exception;<br/><br/>import com.example.ecommerce.dto.ErrorResponse;<br/>import jakarta.persistence.EntityNotFoundException;<br/>import jakarta.persistence.OptimisticLockException;<br/>import jakarta.servlet.http.HttpServletRequest;<br/>import org.springframework.http.HttpStatus;<br/>import org.springframework.http.ResponseEntity;<br/>import org.springframework.web.bind.MethodArgumentNotValidException;<br/>import org.springframework.web.bind.annotation.*;<br/>import java.util.stream.Collectors;<br/><br/>@RestControllerAdvice<br/>public class GlobalExceptionHandler {<br/><br/>    @ExceptionHandler(EntityNotFoundException.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleNotFound(<br/>            EntityNotFoundException ex,<br/>            HttpServletRequest request) {<br/>        return ResponseEntity.status(HttpStatus.NOT_FOUND)<br/>            .body(new ErrorResponse(<br/>                404, \"Not Found\",<br/>                ex.getMessage(),<br/>                request.getRequestURI()));<br/>    }<br/><br/>    @ExceptionHandler(OptimisticLockException.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleConflict(<br/>            OptimisticLockException ex,<br/>            HttpServletRequest request) {<br/>        return ResponseEntity.status(HttpStatus.CONFLICT)<br/>            .body(new ErrorResponse(<br/>                409, \"Conflict\",<br/>                \"Resource was modified by another request. \"<br/>                + \"Please retry with the latest version.\",<br/>                request.getRequestURI()));<br/>    }<br/><br/>    @ExceptionHandler(IllegalStateException.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleBadState(<br/>            IllegalStateException ex,<br/>            HttpServletRequest request) {<br/>        return ResponseEntity.status(HttpStatus.UNPROCESSABLE_ENTITY)<br/>            .body(new ErrorResponse(<br/>                422, \"Unprocessable Entity\",<br/>                ex.getMessage(),<br/>                request.getRequestURI()));<br/>    }<br/><br/>    @ExceptionHandler(IllegalArgumentException.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleBadArgument(<br/>            IllegalArgumentException ex,<br/>            HttpServletRequest request) {<br/>        return ResponseEntity.status(HttpStatus.BAD_REQUEST)<br/>            .body(new ErrorResponse(<br/>                400, \"Bad Request\",<br/>                ex.getMessage(),<br/>                request.getRequestURI()));<br/>    }<br/><br/>    @ExceptionHandler(MethodArgumentNotValidException.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleValidation(<br/>            MethodArgumentNotValidException ex,<br/>            HttpServletRequest request) {<br/>        String errors = ex.getBindingResult()<br/>            .getFieldErrors().stream()<br/>            .map(e -&gt; e.getField() + \": \" + e.getDefaultMessage())<br/>            .collect(Collectors.joining(\"; \"));<br/>        return ResponseEntity.status(HttpStatus.BAD_REQUEST)<br/>            .body(new ErrorResponse(<br/>                400, \"Validation Failed\",<br/>                errors,<br/>                request.getRequestURI()));<br/>    }<br/><br/>    @ExceptionHandler(Exception.class)<br/>    public ResponseEntity&lt;ErrorResponse&gt; handleGeneric(<br/>            Exception ex,<br/>            HttpServletRequest request) {<br/>        return ResponseEntity<br/>            .status(HttpStatus.INTERNAL_SERVER_ERROR)<br/>            .body(new ErrorResponse(<br/>                500, \"Internal Server Error\",<br/>                \"An unexpected error occurred\",<br/>                request.getRequestURI()));<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">错误响应示例</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// GET /api/customers/999 → 404</span><br/>{<br/>    \"status\": 404,<br/>    \"error\": \"Not Found\",<br/>    \"message\": \"Customer not found: id=999\",<br/>    \"path\": \"/api/customers/999\",<br/>    \"timestamp\": \"2026-04-21T10:30:00\"<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// PATCH /api/orders/1/status {\"status\":\"SHIPPED\"}</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 当前状态为 PENDING（不允许直接跳到 SHIPPED） → 422</span><br/>{<br/>    \"status\": 422,<br/>    \"error\": \"Unprocessable Entity\",<br/>    \"message\": \"Invalid transition: PENDING → SHIPPED. Allowed: [PAID, CANCELLED]\",<br/>    \"path\": \"/api/orders/1/status\",<br/>    \"timestamp\": \"2026-04-21T10:31:00\"<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// POST /api/customers {\"name\":\"\",\"email\":\"bad\"} → 400</span><br/>{<br/>    \"status\": 400,<br/>    \"error\": \"Validation Failed\",<br/>    \"message\": \"name: Name is required; email: must be a well-formed email address\",<br/>    \"path\": \"/api/customers\",<br/>    \"timestamp\": \"2026-04-21T10:32:00\"<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.10 Entity View vs 原生 JPA 对比</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">最直观的对比方式是\"做同样的事，看代码量和 SQL 质量的差异\"。以下 4 个场景展示了 Entity View 的优势。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">场景 1：列表查询</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：Repository</span><br/>public interface CustomerJpaRepo<br/>    extends JpaRepository&lt;Customer, Long&gt; {<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：DTO</span><br/>public record CustomerDTO(<br/>    Long id, String name, String email,<br/>    long orderCount) {}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：Service</span><br/>public List&lt;CustomerDTO&gt; listCustomers() {<br/>    return customerJpaRepo.findAll().stream()<br/>        .map(c -&gt; new CustomerDTO(<br/>            c.getId(),<br/>            c.getName(),<br/>            c.getEmail(),<br/>            c.getOrders().size()  <span style=\"color:#6c7086;font-style:italic;\">// N+1 !</span><br/>        ))<br/>        .toList();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 生成 SQL：</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 1. SELECT * FROM customers        (全列)</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 2. SELECT * FROM orders WHERE customer_id=1</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 3. SELECT * FROM orders WHERE customer_id=2</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 4. SELECT * FROM orders WHERE customer_id=3</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ... N+1 条 SQL !</span></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze：View 声明</span><br/>@EntityView(Customer.class)<br/>public interface CustomerListView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    String getEmail();<br/>    @Mapping(\"SIZE(orders)\")<br/>    long getOrderCount();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze：Repository</span><br/>public interface CustomerRepository<br/>    extends EntityViewRepository<br/>            &lt;CustomerListView, Long&gt; {}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze：Service</span><br/>public List&lt;CustomerListView&gt; list() {<br/>    return customerRepo.findAll();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 生成 SQL（仅 1 条）：</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SELECT c.id, c.name, c.email,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   (SELECT COUNT(*)</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    FROM orders o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//    WHERE o.customer_id = c.id)</span><br/><span style=\"color:#6c7086;font-style:italic;\">// FROM customers c</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">场景 2：创建操作</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：</span><br/>public Customer create(CustomerDTO dto) {<br/>    Customer c = new Customer();<br/>    c.setName(dto.name());<br/>    c.setEmail(dto.email());<br/>    c.setPhone(dto.phone());<br/>    Customer saved = customerJpaRepo.save(c);<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 需要手动转回 DTO</span><br/>    return saved;<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// 返回的是 Entity，序列化会暴露所有字段</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 或需要再转一次 DTO</span></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze：</span><br/>public CustomerDetailView create(<br/>        CustomerCreateView view) {<br/>    evm.save(em, view);<br/>    em.flush();<br/>    return evm.find(em,<br/>        CustomerDetailView.class,<br/>        view.getId());<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// 返回 View，序列化精确控制</span><br/><span style=\"color:#6c7086;font-style:italic;\">// CreateView 只暴露可写字段</span><br/><span style=\"color:#6c7086;font-style:italic;\">// DetailView 只暴露可读字段</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">场景 3：更新操作</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：read-modify-write</span><br/>public Customer update(Long id, CustomerDTO dto) {<br/>    Customer c = customerJpaRepo.findById(id)<br/>        .orElseThrow(() -&gt; new EntityNotFoundException(<br/>            \"Customer not found\"));<br/>    c.setName(dto.name());    <span style=\"color:#6c7086;font-style:italic;\">// 手动逐字段赋值</span><br/>    c.setEmail(dto.email());<br/>    return customerJpaRepo.save(c);<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// SQL: SELECT * FROM customers WHERE id=?</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      UPDATE customers SET name=?, email=?,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        phone=?, created_at=?, updated_at=?</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      WHERE id=?</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ↑ 即使 phone 未改，也 SET 了全部列</span></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze：脏追踪 + 精确更新</span><br/>public CustomerDetailView update(Long id,<br/>        CustomerUpdateView view) {<br/>    evm.save(em, view);<br/>    em.flush();<br/>    return evm.find(em,<br/>        CustomerDetailView.class, id);<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// SQL: UPDATE customers</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      SET name=?, email=?</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      WHERE id=?</span><br/><span style=\"color:#6c7086;font-style:italic;\">// ↑ 只更新 UpdateView 声明的字段</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 脏追踪只 SET 实际变更的列</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">场景 4：嵌套关联查询</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 纯 JPA：EntityGraph</span><br/>@EntityGraph(attributePaths = {<br/>    \"customer\", \"items\", \"items.product\"})<br/>Optional&lt;Order&gt; findById(Long id);<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 返回 Order Entity——包含全部字段</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 如果 items 有 100 条，</span><br/><span style=\"color:#6c7086;font-style:italic;\">// items.product 也全量加载</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 序列化需手动裁剪或用 @JsonIgnore</span></p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze：嵌套 View 精确投影</span><br/>@EntityView(Order.class)<br/>public interface OrderDetailView<br/>    extends OrderSummaryView {<br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();<br/>    List&lt;OrderItemView&gt; getItems();<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// 只查需要的列：</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SELECT o.id, o.status, o.total_amount,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   c.name, i.id, p.name, i.quantity,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   i.unit_price, i.subtotal</span><br/><span style=\"color:#6c7086;font-style:italic;\">// FROM orders o</span><br/><span style=\"color:#6c7086;font-style:italic;\">// JOIN customers c ON ...</span><br/><span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN order_items i ON ...</span><br/><span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN products p ON ...</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码量对比统计</h3></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">~180</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">纯 JPA 行数</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">~95</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">Blaze 行数</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">47%</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">代码减少</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">1</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">Blaze SQL 条数</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">N+1</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">纯 JPA SQL 条数</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">22.11 陷阱警示</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">即使 Blaze-Persistence 消除了大量样板代码，在实际使用中仍有几个容易踩坑的地方。本节列举 4 类常见陷阱及其解决方案。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1：LazyInitializationException 与 Entity View</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">问题：</strong>在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Transactional(readOnly = true)</code> 的 Service 方法中返回 Entity View，View 中包含 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"orders\")</code> 关联——Controller 层序列化 JSON 时，事务已关闭，触发 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LazyInitializationException</code>。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：View 在 Controller 层序列化时事务已关闭</span><br/>@EntityView(Customer.class)<br/>public interface CustomerBadView {<br/>    @IdMapping Long getId();<br/>    List&lt;Order&gt; getOrders();  <span style=\"color:#6c7086;font-style:italic;\">// 返回 Entity 而非 View！</span><br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：关联字段必须返回另一个 Entity View</span><br/>@EntityView(Customer.class)<br/>public interface CustomerGoodView {<br/>    @IdMapping Long getId();<br/>    List&lt;OrderSummaryView&gt; getOrders();  <span style=\"color:#6c7086;font-style:italic;\">// View → View</span><br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 或者用 @Mapping 做内联子查询</span><br/>@EntityView(Customer.class)<br/>public interface CustomerCountView {<br/>    @IdMapping Long getId();<br/>    @Mapping(\"SIZE(orders)\")<br/>    long getOrderCount();  <span style=\"color:#6c7086;font-style:italic;\">// 在 SQL 层面计算，不触发延迟加载</span><br/>}</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 22-11 LazyInitializationException 触发路径</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Controller</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Service</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">@Transactional</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">EntityManager</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Jackson</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 Session 已关闭！</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2：UpdatableEntityView 的 flush 顺序</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">问题：</strong>同时修改多个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">UpdatableEntityView</code> 时，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">evm.save()</code> 的调用顺序会影响 SQL 执行顺序——如果存在外键依赖，顺序不当会导致约束违反。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：先删除 Customer 的更新视图，再更新 Order</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 如果 Order 外键引用 Customer → 约束违反</span><br/>evm.save(em, customerUpdateView);  <span style=\"color:#6c7086;font-style:italic;\">// 可能触发 DELETE</span><br/>evm.save(em, orderUpdateView);     <span style=\"color:#6c7086;font-style:italic;\">// 引用已删除的 customer</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：先处理子实体，再处理父实体</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 或者将相关操作放在同一个 @Transactional 方法中，</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 在方法结束时统一 flush</span><br/>evm.save(em, orderUpdateView);<br/>evm.save(em, customerUpdateView);<br/>em.flush();  <span style=\"color:#6c7086;font-style:italic;\">// 统一刷新，Hibernate 自动排序 SQL</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3：缺少 @IdMapping</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">问题：</strong>声明 Entity View 时忘记 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@IdMapping</code>，启动时不一定报错，但运行时会出现奇怪的行为——去重失败、更新视图找不到目标行、分页结果错乱。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：缺少 @IdMapping</span><br/>@EntityView(Customer.class)<br/>public interface CustomerBrokenView {<br/>    Long getId();         <span style=\"color:#6c7086;font-style:italic;\">// 只是普通 getter，不是 ID 映射！</span><br/>    String getName();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：必须有 @IdMapping</span><br/>@EntityView(Customer.class)<br/>public interface CustomerCorrectView {<br/>    @IdMapping            <span style=\"color:#6c7086;font-style:italic;\">// 告诉 Blaze 这是主键字段</span><br/>    Long getId();<br/>    String getName();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 启动时 Blaze 会校验 @UpdatableEntityView 必须有 @IdMapping</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 但只读 @EntityView 如果没有 @IdMapping，</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 只会在集合去重时出现意外行为</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 4：循环 View 引用</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">问题：</strong>Customer View 包含 Order View 列表，Order View 又包含 Customer View——形成循环引用，Jackson 序列化时无限递归，最终 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">StackOverflowError</code>。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 错误：循环引用</span><br/>@EntityView(Customer.class)<br/>public interface CustomerCircularView {<br/>    @IdMapping Long getId();<br/>    List&lt;OrderCircularView&gt; getOrders();<br/>}<br/><br/>@EntityView(Order.class)<br/>public interface OrderCircularView {<br/>    @IdMapping Long getId();<br/>    CustomerCircularView getCustomer();  <span style=\"color:#6c7086;font-style:italic;\">// → 回到 Customer → 回到 Order → ∞</span><br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确：打断循环——Order View 只取 Customer 的标量字段</span><br/>@EntityView(Order.class)<br/>public interface OrderSafeView {<br/>    @IdMapping Long getId();<br/>    @Mapping(\"customer.id\")<br/>    Long getCustomerId();        <span style=\"color:#6c7086;font-style:italic;\">// 只取 ID</span><br/>    @Mapping(\"customer.name\")<br/>    String getCustomerName();    <span style=\"color:#6c7086;font-style:italic;\">// 只取 name</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">// 不再引用完整的 CustomerView</span><br/>}</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱速查表</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">陷阱</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">症状</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">原因</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">解决方案</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LazyInitializationException</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Controller 层序列化时报错</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">View 关联字段返回 Entity 而非 View</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">关联字段始终映射到另一个 Entity View</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Flush 顺序异常</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ConstraintViolationException</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">多个 UpdatableView 的 save 顺序与外键不一致</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">统一 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">em.flush()</code>，或先子后父</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">缺少 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@IdMapping</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">集合去重失败、更新找不到行</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Blaze 无法确定主键字段</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">每个 View 必须有且仅有一个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@IdMapping</code></td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">循环 View 引用</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">StackOverflowError</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">A View → B View → A View</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Mapping(\"b.field\")</code> 标量替代整体引用</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">项目架构</strong>采用 Controller → Service → Repository (EntityViewRepository) → EntityViewManager / CriteriaBuilderFactory → EntityManager → Hibernate → PostgreSQL 分层架构</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Maven 依赖</strong>共需 7 个 Blaze-Persistence 模块：core-api/impl、entity-view-api/impl、integration-hibernate-6.2、integration-spring-data-3.3——版本必须一致</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">JPA Entity</strong> 定义了 5 个核心实体（Customer、Product、Order、OrderItem、Category），其中 Order 包含状态机和乐观锁，Category 支持自关联树形结构</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">BlazeConfig</strong> 只需 1 个 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Configuration</code> 类，创建 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilderFactory</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewManager</code> 两个 Bean，配合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EnableEntityViews</code> 和 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@EnableBlazeRepositories</code> 完成自动装配</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Entity View 投影体系</strong>为每个实体设计了 4 层 View（List/Detail/Create/Update），继承关系复用字段定义，运行时只查 View 声明的列——消除 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code></li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Spring Data Repository</strong> 继承 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">EntityViewRepository</code> 后，派生查询方法自动返回 Entity View，支持 Keyset 分页</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Service 层 CRUD</strong> 使用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">evm.save()</code> 统一处理创建和更新，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">evm.find()</code> 按 View 类型精确投影，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">evm.remove()</code> 按 ID 删除</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">REST Controller</strong> 直接返回 Entity View，Jackson 自动序列化——无需额外 DTO 转换层</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">全局异常处理</strong>通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@RestControllerAdvice</code> 统一拦截 5 类异常，返回一致的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ErrorResponse</code> JSON</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">4 类常见陷阱</strong>：LazyInitializationException（View 关联返回 Entity）、flush 顺序（外键依赖）、缺少 @IdMapping（去重失败）、循环 View 引用（StackOverflow）——每个都有明确的修复策略</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 23 章 · 高级 CRUD 与查询模式</span> 将在本章项目基础上，深入实现动态条件查询、多租户过滤、报表聚合、批量操作等生产级功能。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 22 章</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}